import React, { useEffect, useRef, useState } from 'react';
import './FloatingLines.css';

const FloatingLines = ({
  linesGradient = ['#2F4BC0', '#8000ff'],
  animationSpeed = 1,
  interactive = true,
  bendRadius = 5,
  bendStrength = -0.5,
  mouseDamping = 0.05,
  parallax = true,
  parallaxStrength = 0.2,
}) => {
  const containerRef = useRef(null);
  const canvasRef = useRef(null);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const linesRef = useRef([]);

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;

    if (!canvas || !container) return;

    const ctx = canvas.getContext('2d');

    // Set canvas size
    const resizeCanvas = () => {
      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    };

    resizeCanvas();

    // Initialize lines
    const initLines = () => {
      linesRef.current = [];
      const lineCount = 6;

      for (let i = 0; i < lineCount; i++) {
        linesRef.current.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * 0.5 * animationSpeed,
          vy: (Math.random() - 0.5) * 0.5 * animationSpeed,
          length: 80 + Math.random() * 140,
          angle: Math.random() * Math.PI * 2,
          angularVelocity: (Math.random() - 0.5) * 0.03 * animationSpeed,
        });
      }
    };

    initLines();

    const getColor = (index) => {
      return linesGradient[index % linesGradient.length];
    };

    let animationId;
    let time = 0;

    const animate = () => {
      time += animationSpeed * 0.016;

      // Clear with slight fade
      ctx.fillStyle = 'rgba(0, 0, 0, 0.08)';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      linesRef.current.forEach((line, index) => {
        // Update rotation
        line.angularVelocity += (Math.random() - 0.5) * 0.008 * animationSpeed;
        line.angle += line.angularVelocity;

        // Update position
        line.x += line.vx;
        line.y += line.vy;

        // Apply friction
        line.vx *= 0.98;
        line.vy *= 0.98;

        // Bounce off edges
        if (line.x < 0 || line.x > canvas.width) line.vx *= -1;
        if (line.y < 0 || line.y > canvas.height) line.vy *= -1;

        // Keep in bounds
        line.x = Math.max(0, Math.min(canvas.width, line.x));
        line.y = Math.max(0, Math.min(canvas.height, line.y));

        // Interactive mouse response
        if (interactive && mousePos.x > 0 && mousePos.y > 0) {
          const dx = mousePos.x - line.x;
          const dy = mousePos.y - line.y;
          const distance = Math.sqrt(dx * dx + dy * dy);
          const maxDistance = bendRadius * 60;

          if (distance < maxDistance && distance > 0) {
            const angleToMouse = Math.atan2(dy, dx);
            const force = (1 - distance / maxDistance) * Math.abs(bendStrength);

            if (bendStrength < 0) {
              // Repulsion
              line.vx -= Math.cos(angleToMouse) * force * mouseDamping;
              line.vy -= Math.sin(angleToMouse) * force * mouseDamping;
            } else {
              // Attraction
              line.vx += Math.cos(angleToMouse) * force * mouseDamping;
              line.vy += Math.sin(angleToMouse) * force * mouseDamping;
            }
          }
        }

        // Parallax effect
        if (parallax) {
          line.x += Math.sin(time * 0.3 + index) * parallaxStrength * 0.5;
          line.y += Math.cos(time * 0.3 + index) * parallaxStrength * 0.5;
        }

        // Draw the line
        const color = getColor(index);
        const x1 = line.x - Math.cos(line.angle) * (line.length / 2);
        const y1 = line.y - Math.sin(line.angle) * (line.length / 2);
        const x2 = line.x + Math.cos(line.angle) * (line.length / 2);
        const y2 = line.y + Math.sin(line.angle) * (line.length / 2);

        // Draw outer glow
        ctx.strokeStyle = color;
        ctx.lineWidth = 8;
        ctx.globalAlpha = 0.15;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();

        // Draw middle glow
        ctx.lineWidth = 4;
        ctx.globalAlpha = 0.35;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();

        // Draw main line
        ctx.lineWidth = 2;
        ctx.globalAlpha = 1;
        ctx.beginPath();
        ctx.moveTo(x1, y1);
        ctx.lineTo(x2, y2);
        ctx.stroke();

        ctx.globalAlpha = 1;
      });

      animationId = requestAnimationFrame(animate);
    };

    animate();

    // Mouse tracking
    const handleMouseMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      setMousePos({
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      });
    };

    const handleMouseLeave = () => {
      setMousePos({ x: -1, y: -1 });
    };

    if (interactive) {
      window.addEventListener('mousemove', handleMouseMove);
      container.addEventListener('mouseleave', handleMouseLeave);
    }

    // Resize handler
    const handleResize = () => {
      resizeCanvas();
      initLines();
    };

    window.addEventListener('resize', handleResize);

    return () => {
      cancelAnimationFrame(animationId);
      if (interactive) {
        window.removeEventListener('mousemove', handleMouseMove);
        container.removeEventListener('mouseleave', handleMouseLeave);
      }
      window.removeEventListener('resize', handleResize);
    };
  }, [animationSpeed, interactive, bendRadius, bendStrength, mouseDamping, parallax, parallaxStrength, linesGradient, mousePos]);

  return (
    <div ref={containerRef} className="floating-lines-container">
      <canvas ref={canvasRef} className="floating-lines-canvas" />
    </div>
  );
};

export default FloatingLines;
